    /// 段在内存中的虚拟地址
    pub p_vaddr: usize,
    /// 段的物理地址（未使用）
    pub p_paddr: usize,
    /// 段在文件中的大小
    pub p_filesz: usize,
    /// 段在内存中的大小
    pub p_memsz: usize,
    /// 对齐方式
