pub(crate) fn with_kernel_page_table<T>(f: impl FnOnce() -> T) -> T {
    crate::trap::restore_kernel_page_table();
    let result = f();
    if let Some(task) = crate::task::current_task() {
        if !task.is_kernel {
            task.memory_set.lock().activate();
