        let mut tmp = vec![0u8; sectors_needed * SECTOR_SIZE];
        self.blk
            .lock()
            .read_blocks(sector, &mut tmp)
            .map_err(|_| ())?;
        buf.copy_from_slice(&tmp[skip..skip + buf.len()]);
        Ok(())
    }

    fn write_phys(&self, offset: usize, data: &[u8]) -> Result<(), ()> {
